use crate::types::{DecideInput, DecideOutput};

// Define a constant for the relative tolerance for 6 significant digits.
// For 6 significant digits, we can consider a relative tolerance of 1e-6.
const REL_TOL_SIX_SIG_DIGITS: f64 = 1e-6;
// Also use a small absolute tolerance for cases where numbers are very close to zero.
const ABS_TOL_ZERO: f64 = 1e-9;

// Helper function for real number comparisons with 6 significant digits of precision.
fn realcompare(a: f64, b: f64) -> &'static str {
    let diff = a - b;
    let abs_a = a.abs();
    let abs_b = b.abs();
    let max_abs = abs_a.max(abs_b);

    // If the absolute difference is very small, or the relative difference is small
    if diff.abs() <= ABS_TOL_ZERO || diff.abs() <= REL_TOL_SIX_SIG_DIGITS * max_abs {
        "EQ"
    } else if diff < 0.0 {
        "LT"
    } else { // diff > 0.0
        "GT"
    }
}

// Helper function to calculate the distance between two points (x1, y1) and (x2, y2).
fn distance(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    ((x1 - x2).powi(2) + (y1 - y2).powi(2)).sqrt()
}

// Helper function to calculate the area of a triangle given its vertices.
// Uses the shoelace formula.
fn triangle_area(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    0.5 * (x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)).abs()
}

// Helper function to get the quadrant of a point (x, y).
// Returns 1, 2, 3, or 4. Handles points on axes according to spec.
fn get_quadrant(x: f64, y: f64) -> i32 {
    // The prompt says: "the data point (0,0) is in quadrant I, the point (-1,0) is in quadrant II, the point (0,-1) is in quadrant III, and the point (0,1) is in quadrant I."
    // This implies:
    // (0,0) -> I
    // (x<0, 0) -> II
    // (0, y<0) -> III
    // (0, y>0) -> I
    // (x>0, 0) -> I
    // (x>0, y>0) -> I
    // (x<0, y>0) -> II
    // (x<0, y<0) -> III
    // (x>0, y<0) -> IV

    if x == 0.0 && y == 0.0 { 1 } // Origin case
    else if x == 0.0 { // On Y-axis
        if y > 0.0 { 1 } else { 3 } // (0, y>0) is I, (0, y<0) is III
    } else if y == 0.0 { // On X-axis
        if x > 0.0 { 1 } else { 2 } // (x>0, 0) is I, (x<0, 0) is II
    } else if x > 0.0 && y > 0.0 { 1 }
    else if x < 0.0 && y > 0.0 { 2 }
    else if x < 0.0 && y < 0.0 { 3 }
    else { // x > 0.0 && y < 0.0
        4
    }
}

// Helper function to determine the angle between three points.
// Returns angle in radians. The vertex is p2.
// Returns None if the angle is undefined (p1 == p2 or p2 == p3).
fn angle_between_points(
    x1: f64, y1: f64,
    x2: f64, y2: f64,
    x3: f64, y3: f64
) -> Option<f64> {
    // If vertex is same as one of the other points, angle is undefined.
    if (x1 == x2 && y1 == y2) || (x2 == x3 && y2 == y3) {
        return None;
    }

    let v1x = x1 - x2;
    let v1y = y1 - y2;
    let v2x = x3 - x2;
    let v2y = y3 - y2;

    let dot_product = v1x * v2x + v1y * v2y;
    let mag1 = (v1x.powi(2) + v1y.powi(2)).sqrt();
    let mag2 = (v2x.powi(2) + v2y.powi(2)).sqrt();

    // Avoid division by zero if one of the vectors has zero magnitude
    if mag1 == 0.0 || mag2 == 0.0 {
        return None;
    }

    let cos_theta = dot_product / (mag1 * mag2);

    // Clamp cos_theta to [-1.0, 1.0] due to potential floating point inaccuracies
    let cos_theta_clamped = cos_theta.max(-1.0).min(1.0);

    Some(cos_theta_clamped.acos())
}

// Helper function to calculate distance from point (px, py) to line segment (x1, y1) - (x2, y2).
// Handles the case where x1==x2 and y1==y2.
fn dist_point_to_line(px: f64, py: f64, x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    let line_len_sq = (x2 - x1).powi(2) + (y2 - y1).powi(2);
    if line_len_sq == 0.0 { // p1 and p2 are the same point
        return distance(px, py, x1, y1);
    }

    // Calculate the projection of point P onto the line defined by p1 and p2
    // t = [(px - x1) * (x2 - x1) + (py - y1) * (y2 - y1)] / line_len_sq
    let t = ((px - x1) * (x2 - x1) + (py - y1) * (y2 - y1)) / line_len_sq;

    // If projection falls within the segment
    if t >= 0.0 && t <= 1.0 {
        let proj_x = x1 + t * (x2 - x1);
        let proj_y = y1 + t * (y2 - y1);
        distance(px, py, proj_x, proj_y)
    } else { // Projection falls outside the segment, return distance to the closest endpoint
        let dist_to_p1 = distance(px, py, x1, y1);
        let dist_to_p2 = distance(px, py, x2, y2);
        dist_to_p1.min(dist_to_p2)
    }
}

// Main function to implement the Launch Interceptor Program
pub fn decide(input: &DecideInput) -> DecideOutput {
    let num_points = input.numpoints;

    // Initialize output vectors
    let mut cmv = vec![false; 15];
    let mut pum = vec![vec![false; 15]; 15];
    let mut fuv = vec![false; 15];
    let mut launch = false;

    // Helper to get point coordinates safely
    let get_point = |i: usize| -> (f64, f64) {
        (input.x[i], input.y[i])
    };

    // --- LIC 1: Distance between two consecutive points > LENGTH1 ---
    let mut lic1_met = false;
    if num_points >= 2 {
        for i in 0..(num_points - 1) {
            let (x1, y1) = get_point(i);
            let (x2, y2) = get_point(i + 1);
            if distance(x1, y1, x2, y2) > input.parameters.length1 {
                lic1_met = true;
                break;
            }
        }
    }
    cmv[0] = lic1_met;

    // --- LIC 2: Three consecutive points not contained in a circle of radius RADIUS1 ---
    let mut lic2_met = false;
    if num_points >= 3 {
        for i in 0..(num_points - 2) {
            let (x1, y1) = get_point(i);
            let (x2, y2) = get_point(i + 1);
            let (x3, y3) = get_point(i + 2);

            // Check for collinearity using cross product. If near zero, they are collinear.
            let dx1 = x2 - x1;
            let dy1 = y2 - y1;
            let dx2 = x3 - x1;
            let dy2 = y3 - y1;
            let cross_product = dx1 * dy2 - dx2 * dy1;
            let collinearity_epsilon = 1e-9; // Small tolerance

            if cross_product.abs() < collinearity_epsilon {
                // Points are collinear. They can be contained in a circle if the diameter
                // formed by the two most distant points is <= 2 * RADIUS1.
                let d12 = distance(x1, y1, x2, y2);
                let d13 = distance(x1, y1, x3, y3);
                let d23 = distance(x2, y2, x3, y3);
                let max_dist = d12.max(d13).max(d23);
                if max_dist > 2.0 * input.parameters.radius1 {
                    lic2_met = true;
                    break;
                }
            } else {
                // Points are not collinear, calculate circumradius.
                let a = distance(x2, y2, x3, y3); // dist(p2, p3)
                let b = distance(x1, y1, x3, y3); // dist(p1, p3)
                let c = distance(x1, y1, x2, y2); // dist(p1, p2)
                let area = triangle_area(x1, y1, x2, y2, x3, y3);

                if area < collinearity_epsilon { // Safeguard for near-collinear points
                    let d12 = distance(x1, y1, x2, y2);
                    let d13 = distance(x1, y1, x3, y3);
                    let d23 = distance(x2, y2, x3, y3);
                    let max_dist = d12.max(d13).max(d23);
                    if max_dist > 2.0 * input.parameters.radius1 {
                        lic2_met = true;
                        break;
                    }
                } else {
                    let circumradius = (a * b * c) / (4.0 * area);
                    if circumradius > input.parameters.radius1 {
                        lic2_met = true;
                        break;
                    }
                }
            }
        }
    }
    cmv[1] = lic2_met;

    // --- LIC 3: Angle at vertex > PI + EPSILON or < PI - EPSILON ---
    let mut lic3_met = false;
    if num_points >= 3 {
        let pi = std::f64::consts::PI;
        let epsilon = input.parameters.epsilon;
        for i in 0..(num_points - 2) {
            let (x1, y1) = get_point(i);
            let (x2, y2) = get_point(i + 1); // Vertex
            let (x3, y3) = get_point(i + 2);

            if let Some(angle) = angle_between_points(x1, y1, x2, y2, x3, y3) {
                if angle < pi - epsilon || angle > pi + epsilon {
                    lic3_met = true;
                    break;
                }
            }
        }
    }
    cmv[2] = lic3_met;

    // --- LIC 4: Triangle area > AREA1 ---
    let mut lic4_met = false;
    if num_points >= 3 {
        for i in 0..(num_points - 2) {
            let (x1, y1) = get_point(i);
            let (x2, y2) = get_point(i + 1);
            let (x3, y3) = get_point(i + 2);

            if triangle_area(x1, y1, x2, y2, x3, y3) > input.parameters.area1 {
                lic4_met = true;
                break;
            }
        }
    }
    cmv[3] = lic4_met;

    // --- LIC 5: Q_PTS consecutive points in more than QUADS quadrants ---
    let mut lic5_met = false;
    let q_pts = input.parameters.q_pts;
    let quads = input.parameters.quads;
    if num_points >= 3 && q_pts >= 2 && q_pts <= num_points {
        for i in 0..=(num_points - q_pts) {
            let mut quadrants_present = std::collections::HashSet::new();
            for j in 0..q_pts {
                let (x, y) = get_point(i + j);
                quadrants_present.insert(get_quadrant(x, y));
            }
            if quadrants_present.len() > quads as usize {
                lic5_met = true;
                break;
            }
        }
    }
    cmv[4] = lic5_met;

    // --- LIC 6: Two consecutive points (X[i], Y[i]) and (X[j], Y[j]) where X[j] - X[i] < 0 ---
    let mut lic6_met = false;
    if num_points >= 3 {
        for i in 0..(num_points - 1) {
            let (x_i, _) = get_point(i);
            let (x_j, _) = get_point(i + 1);
            if x_j < x_i {
                lic6_met = true;
                break;
            }
        }
    }
    cmv[5] = lic6_met;

    // --- LIC 7: N_PTS consecutive points, at least one point is > DIST from line joining first and last ---
    let mut lic7_met = false;
    let n_pts = input.parameters.n_pts;
    let dist_param = input.parameters.dist;
    if num_points >= 3 && n_pts >= 3 && n_pts <= num_points {
        for i in 0..=(num_points - n_pts) {
            let (x_start, y_start) = get_point(i);
            let (x_end, y_end) = get_point(i + n_pts - 1);

            if x_start == x_end && y_start == y_end { // Special case: start and end points are identical
                for k in 1..(n_pts - 1) { // Points between start and end (exclusive)
                    let (px, py) = get_point(i + k);
                    if distance(px, py, x_start, y_start) > dist_param {
                        lic7_met = true;
                        break;
                    }
                }
            } else { // Normal case: calculate distance to line segment
                for k in 1..(n_pts - 1) { // Points between start and end (exclusive)
                    let (px, py) = get_point(i + k);
                    if dist_point_to_line(px, py, x_start, y_start, x_end, y_end) > dist_param {
                        lic7_met = true;
                        break;
                    }
                }
            }
            if lic7_met { break; }
        }
    }
    cmv[6] = lic7_met;

    // --- LIC 8: Two points separated by K_PTS consecutive pts are > LENGTH1 apart ---
    let mut lic8_met = false;
    let k_pts = input.parameters.k_pts;
    if num_points >= 3 && k_pts >= 1 && k_pts <= num_points - 2 {
        for i in 0..(num_points - k_pts - 1) {
            let (x1, y1) = get_point(i);
            let (x2, y2) = get_point(i + k_pts + 1);
            if distance(x1, y1, x2, y2) > input.parameters.length1 {
                lic8_met = true;
                break;
            }
        }
    }
    cmv[7] = lic8_met;

    // --- LIC 9: Three points separated by A_PTS and B_PTS pts are NOT contained in circle of radius RADIUS1 ---
    let mut lic9_met = false;
    let a_pts = input.parameters.a_pts;
    let b_pts = input.parameters.b_pts;
    if num_points >= 5 && a_pts >= 1 && b_pts >= 1 && (a_pts + b_pts) <= num_points - 3 {
        for i in 0..=(num_points - a_pts - b_pts - 3) {
            let p1_idx = i;
            let p2_idx = i + a_pts + 1;
            let p3_idx = i + a_pts + b_pts + 2;

            let (x1, y1) = get_point(p1_idx);
            let (x2, y2) = get_point(p2_idx);
            let (x3, y3) = get_point(p3_idx);

            // Logic similar to LIC 2, checking circumradius
            let dx1 = x2 - x1;
            let dy1 = y2 - y1;
            let dx2 = x3 - x1;
            let dy2 = y3 - y1;
            let cross_product = dx1 * dy2 - dx2 * dy1;
            let collinearity_epsilon = 1e-9;

            if cross_product.abs() < collinearity_epsilon {
                let d12 = distance(x1, y1, x2, y2);
                let d13 = distance(x1, y1, x3, y3);
                let d23 = distance(x2, y2, x3, y3);
                let max_dist = d12.max(d13).max(d23);
                if max_dist > 2.0 * input.parameters.radius1 {
                    lic9_met = true;
                    break;
                }
            } else {
                let a = distance(x2, y2, x3, y3);
                let b = distance(x1, y1, x3, y3);
                let c = distance(x1, y1, x2, y2);
                let area = triangle_area(x1, y1, x2, y2, x3, y3);

                if area < collinearity_epsilon {
                    let d12 = distance(x1, y1, x2, y2);
                    let d13 = distance(x1, y1, x3, y3);
                    let d23 = distance(x2, y2, x3, y3);
                    let max_dist = d12.max(d13).max(d23);
                    if max_dist > 2.0 * input.parameters.radius1 {
                        lic9_met = true;
                        break;
                    }
                } else {
                    let circumradius = (a * b * c) / (4.0 * area);
                    if circumradius > input.parameters.radius1 {
                        lic9_met = true;
                        break;
                    }
                }
            }
        }
    }
    cmv[8] = lic9_met;

    // --- LIC 10: Three points separated by C_PTS and D_PTS pts form angle < PI - EPSILON or > PI + EPSILON ---
    let mut lic10_met = false;
    let c_pts = input.parameters.c_pts;
    let d_pts = input.parameters.d_pts;
    if num_points >= 5 && c_pts >= 1 && d_pts >= 1 && (c_pts + d_pts) <= num_points - 3 {
        let pi = std::f64::consts::PI;
        let epsilon = input.parameters.epsilon;
        for i in 0..=(num_points - c_pts - d_pts - 3) {
            let p1_idx = i;
            let p2_idx = i + c_pts + 1; // Vertex
            let p3_idx = i + c_pts + d_pts + 2;

            let (x1, y1) = get_point(p1_idx);
            let (x2, y2) = get_point(p2_idx);
            let (x3, y3) = get_point(p3_idx);

            if let Some(angle) = angle_between_points(x1, y1, x2, y2, x3, y3) {
                if angle < pi - epsilon || angle > pi + epsilon {
                    lic10_met = true;
                    break;
                }
            }
        }
    }
    cmv[9] = lic10_met;

    // --- LIC 11: Three points separated by E_PTS and F_PTS pts form triangle with area > AREA1 ---
    let mut lic11_met = false;
    let e_pts = input.parameters.e_pts;
    let f_pts = input.parameters.f_pts;
    if num_points >= 5 && e_pts >= 1 && f_pts >= 1 && (e_pts + f_pts) <= num_points - 3 {
        for i in 0..=(num_points - e_pts - f_pts - 3) {
            let p1_idx = i;
            let p2_idx = i + e_pts + 1;
            let p3_idx = i + e_pts + f_pts + 2;

            let (x1, y1) = get_point(p1_idx);
            let (x2, y2) = get_point(p2_idx);
            let (x3, y3) = get_point(p3_idx);

            if triangle_area(x1, y1, x2, y2, x3, y3) > input.parameters.area1 {
                lic11_met = true;
                break;
            }
        }
    }
    cmv[10] = lic11_met;

    // --- LIC 12: Two points separated by G_PTS consecutive pts, where X[j] - X[i] < 0 ---
    let mut lic12_met = false;
    let g_pts = input.parameters.g_pts;
    if num_points >= 3 && g_pts >= 1 && g_pts <= num_points - 2 {
        for i in 0..(num_points - g_pts - 1) {
            let (x_i, _) = get_point(i);
            let (x_j, _) = get_point(i + g_pts + 1);
            if x_j < x_i {
                lic12_met = true;
                break;
            }
        }
    }
    cmv[11] = lic12_met;

    // --- LIC 13: Two points separated by K_PTS pts are > LENGTH1 apart AND < LENGTH2 apart ---
    let mut lic13_met = false;
    let k_pts_lic13 = input.parameters.k_pts; // k_pts is reused from LIC 8, let's be explicit
    if num_points >= 3 && k_pts_lic13 >= 1 && k_pts_lic13 <= num_points - 2 {
        let mut cond1_met = false; // distance > LENGTH1
        let mut cond2_met = false; // distance < LENGTH2

        for i in 0..(num_points - k_pts_lic13 - 1) {
            let (x1, y1) = get_point(i);
            let (x2, y2) = get_point(i + k_pts_lic13 + 1);
            let dist = distance(x1, y1, x2, y2);

            if dist > input.parameters.length1 {
                cond1_met = true;
            }
            if dist < input.parameters.length2 {
                cond2_met = true;
            }
            if cond1_met && cond2_met {
                lic13_met = true;
                break;
            }
        }
    }
    cmv[12] = lic13_met;

    // --- LIC 14: Three points separated by A_PTS and B_PTS pts cannot be contained in circle of RADIUS1 AND CAN be contained in circle of RADIUS2 ---
    let mut lic14_met = false;
    let a_pts_lic14 = input.parameters.a_pts;
    let b_pts_lic14 = input.parameters.b_pts;
    if num_points >= 5 && a_pts_lic14 >= 1 && b_pts_lic14 >= 1 && (a_pts_lic14 + b_pts_lic14) <= num_points - 3 {
        let mut cond1_met = false; // circumradius > RADIUS1
        let mut cond2_met = false; // circumradius <= RADIUS2

        for i in 0..=(num_points - a_pts_lic14 - b_pts_lic14 - 3) {
            let p1_idx = i;
            let p2_idx = i + a_pts_lic14 + 1;
            let p3_idx = i + a_pts_lic14 + b_pts_lic14 + 2;

            let (x1, y1) = get_point(p1_idx);
            let (x2, y2) = get_point(p2_idx);
            let (x3, y3) = get_point(p3_idx);

            // Calculate circumradius logic (similar to LIC 2 and 9)
            let dx1 = x2 - x1;
            let dy1 = y2 - y1;
            let dx2 = x3 - x1;
            let dy2 = y3 - y1;
            let cross_product = dx1 * dy2 - dx2 * dy1;
            let collinearity_epsilon = 1e-9;

            if cross_product.abs() < collinearity_epsilon { // Collinear case
                let d12 = distance(x1, y1, x2, y2);
                let d13 = distance(x1, y1, x3, y3);
                let d23 = distance(x2, y2, x3, y3);
                let max_dist = d12.max(d13).max(d23);

                // For collinear points:
                // Condition 1: max_dist > 2 * RADIUS1 (cannot be contained in circle of RADIUS1)
                if max_dist > 2.0 * input.parameters.radius1 { cond1_met = true; }
                // Condition 2: max_dist <= 2 * RADIUS2 (can be contained in circle of RADIUS2)
                if max_dist <= 2.0 * input.parameters.radius2 { cond2_met = true; }

            } else { // Non-collinear case
                let a = distance(x2, y2, x3, y3);
                let b = distance(x1, y1, x3, y3);
                let c = distance(x1, y1, x2, y2);
                let area = triangle_area(x1, y1, x2, y2, x3, y3);

                if area >= collinearity_epsilon { // Ensure area is not zero (not collinear)
                    let circumradius = (a * b * c) / (4.0 * area);
                    // Condition 1: circumradius > RADIUS1
                    if circumradius > input.parameters.radius1 { cond1_met = true; }
                    // Condition 2: circumradius <= RADIUS2
                    if circumradius <= input.parameters.radius2 { cond2_met = true; }
                } else { // Fallback for near-collinear points if area calculation yields near zero
                    let d12 = distance(x1, y1, x2, y2);
                    let d13 = distance(x1, y1, x3, y3);
                    let d23 = distance(x2, y2, x3, y3);
                    let max_dist = d12.max(d13).max(d23);

                    if max_dist > 2.0 * input.parameters.radius1 { cond1_met = true; }
                    if max_dist <= 2.0 * input.parameters.radius2 { cond2_met = true; }
                }
            }

            if cond1_met && cond2_met {
                lic14_met = true;
                break;
            }
        }
    }
    cmv[13] = lic14_met;

    // --- LIC 15: Three points separated by E_PTS and F_PTS pts form triangle with area > AREA1 AND < AREA2 ---
    let mut lic15_met = false;
    let e_pts_lic15 = input.parameters.e_pts;
    let f_pts_lic15 = input.parameters.f_pts;
    if num_points >= 5 && e_pts_lic15 >= 1 && f_pts_lic15 >= 1 && (e_pts_lic15 + f_pts_lic15) <= num_points - 3 {
        let mut cond1_met = false; // area > AREA1
        let mut cond2_met = false; // area < AREA2

        for i in 0..=(num_points - e_pts_lic15 - f_pts_lic15 - 3) {
            let p1_idx = i;
            let p2_idx = i + e_pts_lic15 + 1;
            let p3_idx = i + e_pts_lic15 + f_pts_lic15 + 2;

            let (x1, y1) = get_point(p1_idx);
            let (x2, y2) = get_point(p2_idx);
            let (x3, y3) = get_point(p3_idx);

            let area = triangle_area(x1, y1, x2, y2, x3, y3);

            if area > input.parameters.area1 { cond1_met = true; }
            if area < input.parameters.area2 { cond2_met = true; }

            if cond1_met && cond2_met {
                lic15_met = true;
                break;
            }
        }
    }
    cmv[14] = lic15_met;


    // --- PUM Calculation ---
    for i in 0..15 {
        for j in 0..15 {
            match input.lcm[i][j] {
                "NOTUSED" => pum[i][j] = true,
                "ANDD" => pum[i][j] = cmv[i] && cmv[j],
                "ORR" => pum[i][j] = cmv[i] || cmv[j],
                _ => (), // Should not happen with valid LCM input
            }
        }
    }

    // --- FUV Calculation ---
    for i in 0..15 {
        // PUM[i, i] is diagonal, these are `pum_diag` values from input.
        // FUV[i] is true if PUM[i, i] is false (meaning this LIC *should not* hold back launch).
        // AND all elements in row i of PUM are true.

        let mut all_row_i_are_true = true;
        for j in 0..15 {
            if !pum[i][j] {
                all_row_i_are_true = false;
                break;
            }
        }

        // The spec says: "FUV[i] should be set to true if PUM[i, i] is false (indicating that the associated LIC should not hold back launch) or if all elements in PUM row i are true."
        // However, the input `pum_diag` is Vec<bool> for LIC 1..15.
        // This `pum_diag` seems to be the actual PUM[i,i] values for the purpose of FUV calculation.
        // The prompt states: "pum_diag: Vec<bool> — length 15; diagonal PUM for LIC 1..15."
        // And then: "FUV[i] should be set to true if PUM[i, i] is false (indicating that the associated LIC should not hold back launch) or if all elements in PUM row i are true."
        // This implies we need to use the provided `pum_diag` for the PUM[i,i] check.

        // Let's re-evaluate the FUV logic based on this:
        // `fuv[i]` is true if `input.pum_diag[i]` is false OR all elements in row `i` of calculated `pum` are true.
        // Note that the input `pum_diag` is 1-indexed in description (LIC 1..15) but a Vec<bool> is 0-indexed.
        // Assuming `input.pum_diag[i]` corresponds to LIC `i+1`.

        if !input.pum_diag[i] || all_row_i_are_true {
            fuv[i] = true;
        } else {
            fuv[i] = false;
        }
    }

    // --- Launch Decision ---
    launch = fuv.iter().all(|&x| x);

    // Return the results
    DecideOutput::from_fixed(cmv, pum, fuv, launch)
}
